import{_ as s,o as n,c as p,a4 as t}from"./chunks/framework.ChErgFjV.js";const u=JSON.parse('{"title":"第五章 教学设计","description":"","frontmatter":{"title":"第五章 教学设计","date":"2026-07-08T00:00:00.000Z","tags":["教师资格考试","数学学科知识","教学设计"]},"headers":[],"relativePath":"teacher-exam/math-subject/chapter5.md","filePath":"teacher-exam/math-subject/chapter5.md","lastUpdated":1783503035000}'),l={name:"teacher-exam/math-subject/chapter5.md"};function e(o,a,i,r,c,d){return n(),p("div",null,[...a[0]||(a[0]=[t(`<h1 id="第五章-教学设计" tabindex="-1">第五章 教学设计 <a class="header-anchor" href="#第五章-教学设计" aria-label="Permalink to &quot;第五章 教学设计&quot;">​</a></h1><blockquote><p>本章考情：教学设计题 30 分，必考 最重要的一章，需要大量练习写教案</p></blockquote><hr><h2 id="_5-1-教学设计基本环节-🔴🔴🔴" tabindex="-1">5.1 教学设计基本环节 🔴🔴🔴 <a class="header-anchor" href="#_5-1-教学设计基本环节-🔴🔴🔴" aria-label="Permalink to &quot;5.1 教学设计基本环节 🔴🔴🔴&quot;">​</a></h2><table tabindex="0"><thead><tr><th>环节</th><th>内容</th><th>注意事项</th></tr></thead><tbody><tr><td>教材分析 🔴🔴</td><td>地位与作用、前后联系、重点难点</td><td>要说清&quot;为什么这是重点&quot;</td></tr><tr><td>学情分析 🔴</td><td>已有基础、认知困难、学习兴趣</td><td>要具体，不能泛泛而谈</td></tr><tr><td>教学目标 🔴🔴🔴</td><td>四基目标+核心素养</td><td>行为动词要准确</td></tr><tr><td>教学重难点 🔴🔴</td><td>重点+难点+突破策略</td><td>重点≠难点</td></tr><tr><td>教学过程 🔴🔴🔴</td><td>情境→探究→巩固→小结→作业</td><td>每个环节写设计意图</td></tr><tr><td>板书设计</td><td>主板书+副板书</td><td>清晰、结构化</td></tr><tr><td>教学反思</td><td>课后对教学过程的反思</td><td>体现教学智慧</td></tr></tbody></table><hr><h2 id="_5-2-教学目标设定-🔴🔴🔴" tabindex="-1">5.2 教学目标设定 🔴🔴🔴 <a class="header-anchor" href="#_5-2-教学目标设定-🔴🔴🔴" aria-label="Permalink to &quot;5.2 教学目标设定 🔴🔴🔴&quot;">​</a></h2><h3 id="三维目标-传统写法" tabindex="-1">三维目标（传统写法） <a class="header-anchor" href="#三维目标-传统写法" aria-label="Permalink to &quot;三维目标（传统写法）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 知识与技能：理解/掌握……</span></span>
<span class="line"><span>2. 过程与方法：经历……过程，发展……能力</span></span>
<span class="line"><span>3. 情感态度与价值观：体会……，培养……</span></span></code></pre></div><h3 id="新课标四基目标写法-🔴🔴🔴" tabindex="-1">新课标四基目标写法 🔴🔴🔴 <a class="header-anchor" href="#新课标四基目标写法-🔴🔴🔴" aria-label="Permalink to &quot;新课标四基目标写法 🔴🔴🔴&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 理解/掌握……（基础知识）</span></span>
<span class="line"><span>2. 经历……过程，能够……（基本技能+基本活动经验）</span></span>
<span class="line"><span>3. 体会……思想方法，发展……素养（基本思想+核心素养）</span></span></code></pre></div><h3 id="行为动词层次-🔴🔴" tabindex="-1">行为动词层次 🔴🔴 <a class="header-anchor" href="#行为动词层次-🔴🔴" aria-label="Permalink to &quot;行为动词层次 🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>层次</th><th>动词</th><th>含义</th></tr></thead><tbody><tr><td>了解</td><td>知道、认识、辨认</td><td>能回忆和识别</td></tr><tr><td>理解 🔴</td><td>解释、说明、判断</td><td>能解释含义和关系</td></tr><tr><td>掌握 🔴</td><td>运用、证明、推导</td><td>能在新情境中运用</td></tr><tr><td>运用 🔴🔴</td><td>灵活运用、综合运用</td><td>能综合解决复杂问题</td></tr></tbody></table><hr><h2 id="_5-3-教学重难点-🔴🔴" tabindex="-1">5.3 教学重难点 🔴🔴 <a class="header-anchor" href="#_5-3-教学重难点-🔴🔴" aria-label="Permalink to &quot;5.3 教学重难点 🔴🔴&quot;">​</a></h2><p><strong>重点</strong>：本节课最核心的知识或技能，由教材地位决定 <strong>难点</strong>：学生不容易理解或容易出错的内容，由学生认知水平决定</p><p><strong>确定重点的方法</strong>：</p><ol><li>看本节内容在章节中的核心地位</li><li>看是否为后续学习的基础</li></ol><p><strong>突破难点的方法</strong> 🔴🔴：</p><ol><li>直观演示 — 化抽象为具体</li><li>分步讲解 — 降低认知坡度</li><li>类比迁移 — 从已知到未知</li><li>变式练习 — 从不同角度理解</li></ol><hr><h2 id="_5-4-教学过程设计模板-🔴🔴🔴" tabindex="-1">5.4 教学过程设计模板 🔴🔴🔴 <a class="header-anchor" href="#_5-4-教学过程设计模板-🔴🔴🔴" aria-label="Permalink to &quot;5.4 教学过程设计模板 🔴🔴🔴&quot;">​</a></h2><h3 id="通用模板" tabindex="-1">通用模板 <a class="header-anchor" href="#通用模板" aria-label="Permalink to &quot;通用模板&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>一、创设情境，引入新课（3-5分钟）</span></span>
<span class="line"><span>   情境内容：……</span></span>
<span class="line"><span>   设计意图：激发兴趣，引出课题</span></span>
<span class="line"><span></span></span>
<span class="line"><span>二、探究新知（15-20分钟）</span></span>
<span class="line"><span>   活动1：……</span></span>
<span class="line"><span>   设计意图：……</span></span>
<span class="line"><span>   活动2：……</span></span>
<span class="line"><span>   设计意图：……</span></span>
<span class="line"><span>   活动3：……</span></span>
<span class="line"><span>   设计意图：……</span></span>
<span class="line"><span></span></span>
<span class="line"><span>三、巩固练习（10-15分钟）</span></span>
<span class="line"><span>   基础题：……（巩固基础）</span></span>
<span class="line"><span>   提高题：……（深化理解）</span></span>
<span class="line"><span>   设计意图：分层练习，检验目标达成</span></span>
<span class="line"><span></span></span>
<span class="line"><span>四、课堂小结（3-5分钟）</span></span>
<span class="line"><span>   引导学生从知识和方法两方面总结</span></span>
<span class="line"><span>   设计意图：梳理知识，提炼方法</span></span>
<span class="line"><span></span></span>
<span class="line"><span>五、布置作业</span></span>
<span class="line"><span>   必做题：……</span></span>
<span class="line"><span>   选做题：……</span></span>
<span class="line"><span>   设计意图：分层作业，巩固提升</span></span></code></pre></div><h3 id="不同课型的教学设计-🔴🔴" tabindex="-1">不同课型的教学设计 🔴🔴 <a class="header-anchor" href="#不同课型的教学设计-🔴🔴" aria-label="Permalink to &quot;不同课型的教学设计 🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>课型</th><th>重点环节</th><th>设计要点</th></tr></thead><tbody><tr><td>概念课 🔴🔴🔴</td><td>概念的形成过程</td><td>丰富实例→概括本质→辨析理解→应用巩固</td></tr><tr><td>定理/公式课 🔴🔴</td><td>定理的发现与证明</td><td>创设情境→提出猜想→分析证明→应用拓展</td></tr><tr><td>习题课 🔴</td><td>解题方法总结</td><td>典型例题→方法提炼→变式训练→反思提升</td></tr><tr><td>复习课 🔴</td><td>知识结构构建</td><td>知识梳理→体系构建→综合应用→查漏补缺</td></tr></tbody></table><hr><h2 id="_5-5-常考课题教学设计-🔴🔴🔴" tabindex="-1">5.5 常考课题教学设计 🔴🔴🔴 <a class="header-anchor" href="#_5-5-常考课题教学设计-🔴🔴🔴" aria-label="Permalink to &quot;5.5 常考课题教学设计 🔴🔴🔴&quot;">​</a></h2><h3 id="课题1-二次函数的图像与性质-🔴🔴🔴" tabindex="-1">课题1：二次函数的图像与性质 🔴🔴🔴 <a class="header-anchor" href="#课题1-二次函数的图像与性质-🔴🔴🔴" aria-label="Permalink to &quot;课题1：二次函数的图像与性质 🔴🔴🔴&quot;">​</a></h3><p><strong>教材分析</strong>：二次函数是初中数学的核心内容，是函数知识的深化，也是高中函数学习的基础。</p><p><strong>教学目标</strong>：</p><ol><li>理解二次函数 y=ax² 的图像是抛物线，掌握其开口方向、对称轴、顶点等性质</li><li>经历描点法作图和性质探究的过程，发展直观想象和数学抽象素养</li><li>体会数形结合思想，感受数学的对称美</li></ol><p><strong>教学重点</strong>：二次函数 y=ax² 的图像与性质 <strong>教学难点</strong>：a 的正负对开口方向的影响，|a| 对开口大小的影响</p><p><strong>教学过程</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>一、创设情境</span></span>
<span class="line"><span>   展示喷泉水流、抛物运动的图片</span></span>
<span class="line"><span>   提问：这些运动轨迹有什么共同特征？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>二、探究新知</span></span>
<span class="line"><span>   活动1：描点法画出 y=x&amp;sup2; 的图像</span></span>
<span class="line"><span>   - 列表取值（x=-3,-2,-1,0,1,2,3）</span></span>
<span class="line"><span>   - 描点连线，观察图像形状</span></span>
<span class="line"><span>   - 归纳：抛物线，开口向上，关于y轴对称，顶点在原点</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   活动2：在同一坐标系中画 y=x&amp;sup2; 和 y=-x&amp;sup2;</span></span>
<span class="line"><span>   - 比较开口方向</span></span>
<span class="line"><span>   - 归纳：a&gt;0开口向上，a&lt;0开口向下</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   活动3：画 y=2x&amp;sup2; 和 y=&amp;frac12;x&amp;sup2; 的图像</span></span>
<span class="line"><span>   - 比较开口大小</span></span>
<span class="line"><span>   - 归纳：|a|越大，开口越小（抛物线越&quot;窄&quot;）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>三、巩固练习</span></span>
<span class="line"><span>   基础题：说出 y=3x&amp;sup2;、y=-2x&amp;sup2; 的开口方向和对称轴</span></span>
<span class="line"><span>   提高题：已知抛物线 y=ax&amp;sup2; 经过点(2,8)，求a的值</span></span>
<span class="line"><span></span></span>
<span class="line"><span>四、课堂小结</span></span>
<span class="line"><span>   知识：y=ax&amp;sup2; 的图像是抛物线</span></span>
<span class="line"><span>   方法：描点法、数形结合</span></span>
<span class="line"><span></span></span>
<span class="line"><span>五、布置作业</span></span>
<span class="line"><span>   必做题：课本习题</span></span>
<span class="line"><span>   选做题：探究 y=a(x-h)&amp;sup2;+k 的图像</span></span></code></pre></div><h3 id="课题2-全等三角形的判定-sas-🔴🔴" tabindex="-1">课题2：全等三角形的判定（SAS）🔴🔴 <a class="header-anchor" href="#课题2-全等三角形的判定-sas-🔴🔴" aria-label="Permalink to &quot;课题2：全等三角形的判定（SAS）🔴🔴&quot;">​</a></h3><p><strong>教学重点</strong>：SAS 判定方法的理解和应用 <strong>教学难点</strong>：证明过程中&quot;对应&quot;关系的确定</p><p><strong>教学过程</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>一、情境引入</span></span>
<span class="line"><span>   展示两块完全相同的三角板</span></span>
<span class="line"><span>   提问：如何判定两个三角形全等？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>二、探究新知</span></span>
<span class="line"><span>   活动1：画&amp;triangle;ABC，使AB=3cm，&amp;angle;A=60°，AC=4cm</span></span>
<span class="line"><span>   - 剪下三角形，与同桌比较</span></span>
<span class="line"><span>   - 发现：两边和夹角确定→三角形唯一确定</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   活动2：归纳 SAS 判定方法</span></span>
<span class="line"><span>   - 文字语言：两边和它们的夹角分别相等的两个三角形全等</span></span>
<span class="line"><span>   - 符号语言：在&amp;triangle;ABC和&amp;triangle;DEF中，</span></span>
<span class="line"><span>     AB=DE，&amp;angle;B=&amp;angle;E，BC=EF</span></span>
<span class="line"><span>     &amp;rArr; &amp;triangle;ABC&amp;cong;&amp;triangle;DEF(SAS)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   活动3：强调&quot;夹角&quot;</span></span>
<span class="line"><span>   - 反例：两边和其中一边的对角（SSA）不能判定全等</span></span>
<span class="line"><span></span></span>
<span class="line"><span>三、巩固练习</span></span>
<span class="line"><span>   基础题：直接用SAS判定全等</span></span>
<span class="line"><span>   提高题：需先证出边或角相等，再用SAS</span></span>
<span class="line"><span></span></span>
<span class="line"><span>四、小结</span></span>
<span class="line"><span>   知识：SAS判定方法</span></span>
<span class="line"><span>   方法：找对应边角→书写规范</span></span>
<span class="line"><span>   注意：必须是对应的&quot;夹角&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>五、作业</span></span></code></pre></div><hr><h2 id="_5-6-板书设计-🔴" tabindex="-1">5.6 板书设计 🔴 <a class="header-anchor" href="#_5-6-板书设计-🔴" aria-label="Permalink to &quot;5.6 板书设计 🔴&quot;">​</a></h2><p><strong>板书要求</strong>：</p><ol><li>主板书 — 课题、定义、定理、公式（保留到下课）</li><li>副板书 — 例题、演算过程（可擦除）</li><li>结构清晰、重点突出、书写工整</li></ol><hr><h2 id="近三年真题精选" tabindex="-1">近三年真题精选 <a class="header-anchor" href="#近三年真题精选" aria-label="Permalink to &quot;近三年真题精选&quot;">​</a></h2><p><strong>1.</strong>（2024上）教学设计题：请为&quot;勾股定理&quot;设计一个完整的教学方案（含教学目标、重难点、教学过程）。</p><blockquote><p><strong>参考答案要点</strong>： 教学目标：①理解勾股定理的内容；②经历勾股定理的发现过程；③体会数形结合思想。 重点：勾股定理的理解和应用。难点：勾股定理的发现和证明。 教学过程：①情境引入（展示直角三角形三边关系）；②探究发现（画方格纸上的直角三角形，数格子发现 a²+b²=c²）；③证明（赵爽弦图/面积法）；④应用（求直角三角形边长）；⑤小结（知识+方法）。</p></blockquote><p><strong>2.</strong>（2023下）教学设计题：请为&quot;一元一次方程的解法（移项）&quot;设计教学过程。</p><blockquote><p><strong>参考答案要点</strong>： ①复习引入：回顾等式性质；②探究新知：通过具体方程 2x+5=3x-2 引导发现移项规律；③归纳：移项要变号；④巩固练习：由简到繁，先不含分母→含分母；⑤小结：移项法则+解方程步骤。</p></blockquote><p><strong>3.</strong>（2024上）下列教学目标中，表述最规范的是（ ）</p><p>A. 让学生理解二次函数 🔴   B. 培养学生数学能力   C. 掌握二次函数 y=ax²+bx+c 的图像与性质 🔴   D. 提高学生分析问题能力</p><blockquote><p><strong>答案</strong>：C   行为动词准确，内容具体可检测</p></blockquote><p><strong>4.</strong>（2023下）简述确定教学重点和难点的方法。</p><blockquote><p><strong>答</strong>：确定重点的方法：①看本节内容在单元/章节中的核心地位；②看是否为后续学习的基础；③看课标的要求程度。确定难点的方法：①分析学生已有认知水平与本节内容的差距；②预判学生容易出错或混淆的地方；③考虑内容的抽象程度和思维跨度。</p></blockquote><p><strong>5.</strong>（2023上）案例分析：某教师在&quot;平行四边形性质&quot;教学中，直接给出&quot;平行四边形对边相等、对角相等、对角线互相平分&quot;三个性质，然后让学生做练习。请评价并给出改进建议。</p><blockquote><p><strong>答</strong>：该教师的教学存在不足：①忽视了性质的探究过程，学生缺乏发现体验；②没有体现&quot;学生主体&quot;理念；③不利于培养学生的几何推理能力。改进：①设计操作活动，让学生测量、比较、猜想；②引导学生用全等三角形证明猜想；③从&quot;发现→猜想→证明→应用&quot;的完整过程中学习。</p></blockquote><p><strong>6.</strong>（2024上）教学设计中的&quot;设计意图&quot;应该写什么？</p><blockquote><p><strong>答</strong>：设计意图应说明：①该环节对应哪个教学目标；②该环节体现了什么教学理念或策略；③该环节对学生学习的促进作用。例如：&quot;通过画图操作让学生直观感知，体现数形结合思想，发展直观想象素养。&quot;</p></blockquote><p><strong>7.</strong>（2023下）请为&quot;圆的切线判定定理&quot;设计教学过程。</p><blockquote><p><strong>参考答案要点</strong>：①复习引入：圆的切线定义和性质；②探究：用直尺在圆上尝试画切线→发现切线与半径垂直；③归纳：经过半径外端且垂直于这条半径的直线是圆的切线；④辨析：&quot;经过半径外端&quot;和&quot;垂直于半径&quot;缺一不可；⑤应用：过圆上一点画切线。</p></blockquote><p><strong>8.</strong>（2024上）简述&quot;讲练结合法&quot;在数学教学中的应用策略。</p><blockquote><p><strong>答</strong>：①精讲精练：讲在关键处，练在点子上；②讲练交替：讲一个知识点练一道题，避免集中讲完再练；③分层练习：基础题→提高题→拓展题；④反馈及时：学生练习后及时点评纠错；⑤重视过程：不只讲答案，更要讲思路和方法。</p></blockquote><p><strong>9.</strong>（2023上）教学设计题：请为&quot;中位数和众数&quot;设计完整的教学方案。</p><blockquote><p><strong>参考答案要点</strong>：①情境引入：某公司招聘，声称平均工资8000元，但多数员工不到5000元→引出平均数的局限性；②探究：引入中位数和众数的概念；③比较：平均数、中位数、众数各自的特点和适用场景；④应用：选择合适的统计量分析实际数据；⑤小结：三个统计量的联系与区别。</p></blockquote><p><strong>10.</strong>（2024上）评析以下教学目标设定的优缺点：&quot;使学生理解一次函数的图像是一条直线。&quot;</p><blockquote><p><strong>答</strong>：优点：内容指向明确（一次函数的图像）。缺点：①&quot;使学生&quot;体现了教师本位，应以学生为主体；②&quot;理解&quot;层次较低，应上升到&quot;掌握&quot;或&quot;运用&quot;；③缺少过程性目标和素养目标。修改建议：&quot;理解一次函数 y=kx+b 的图像是直线，经历描点作图和探究性质的过程，体会数形结合思想，发展直观想象素养。&quot;</p></blockquote>`,66)])])}const g=s(l,[["render",e]]);export{u as __pageData,g as default};
